#include <vector>
#include <queue>
using namespace std;

long long comp(long long t, long long n, const vector<vector<long long>>& edges) {
    vector<vector<long long>> adj(n);
    for (const auto& e : edges) {
        if (e[2] > t) {
            long long u = e[0];
            long long v = e[1];
            adj[u].push_back(v);
            adj[v].push_back(u);
        }
    }
    vector<bool> visited(n, false);
    long long count = 0;
    for (long long i = 0; i < n; i++) {
        if (!visited[i]) {
            count++;
            queue<long long> q;
            q.push(i);
            visited[i] = true;
            while (!q.empty()) {
                long long cur = q.front();
                q.pop();
                for (auto neighbor : adj[cur]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true;
                        q.push(neighbor);
                    }
                }
            }
        }
    }
    return count;
}

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    long long max_time = 0;
    for (const auto& e : edges) {
        if (e[2] > max_time) 
            max_time = e[2];
    }
    long long low = 0;
    long long high = max_time + 1;
    while (low < high) {
        long long mid = low + (high - low) / 2;
        if (comp(mid, n, edges) >= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
```

### Explanation
1. **Binary Search**: The binary search is initialized with `low` set to 0 and `high` set to the maximum edge time + 1. This range covers all possible values of `t` from no edges removed (all edges present) to all edges removed (graph completely disconnected).
2. **Component Counting Function (`comp`)**:
   - **Graph Construction**: For a given `t`, the graph is built by including edges with `time > t`.
   - **BFS for Components**: The BFS traverses each node, marking visited nodes to count connected components. Each unvisited node initiates a new BFS, incrementing the component count.
3. **Binary Search Execution**: The binary search checks if the current midpoint `t` results in at least `k` components. If yes, it searches lower values; otherwise, it searches higher values. The loop exits when `low` meets `high`, returning the minimal `t` that satisfies the condition.

This approach efficiently narrows down the search space using binary search and accurately counts components for each candidate `t` using BFS, ensuring optimal performance even for large graphs.

