using namespace std;

long long find_root(vector<long long>& parent, long long x) {
    long long root = x;
    while (root != parent[root]) {
        root = parent[root];
    }
    long long cur = x;
    while (cur != root) {
        long long next = parent[cur];
        parent[cur] = root;
        cur = next;
    }
    return root;
}

long long count_components(long long n, const vector<vector<long long>>& edges, long long T) {
    vector<long long> parent(n);
    vector<long long> rank(n, 0);
    for (long long i = 0; i < n; i++) {
        parent[i] = i;
    }

    long long comp = n;
    for (const auto& e : edges) {
        if (e[2] > T) {
            long long u = e[0];
            long long v = e[1];
            long long ru = find_root(parent, u);
            long long rv = find_root(parent, v);
            if (ru != rv) {
                comp--;
                if (rank[ru] < rank[rv]) {
                    parent[ru] = rv;
                } else if (rank[rv] < rank[ru]) {
                    parent[rv] = ru;
                } else {
                    parent[rv] = ru;
                    rank[ru]++;
                }
            }
        }
    }
    return comp;
}

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (n == 0) {
        return 0;
    }

    long long max_time_val = 0;
    for (const auto& e : edges) {
        if (e[2] > max_time_val) {
            max_time_val = e[2];
        }
    }

    long long low = -1;
    long long high = max_time_val + 1;

    while (high - low > 1) {
        long long mid = low + (high - low) / 2;
        long long comp = count_components(n, edges, mid);
        if (comp >= k) {
            high = mid;
        } else {
            low = mid;
        }
    }

    return high;
}
