#include <vector>
#include <algorithm>
using namespace std;

struct DSU {
    vector<long long> parent;
    vector<long long> rank;
    long long comp;
    DSU(long long n) : parent(n), rank(n, 0), comp(n) {
        for (long long i = 0; i < n; i++) {
            parent[i] = i;
        }
    }
    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    bool merge(long long x, long long y) {
        long long xr = find(x);
        long long yr = find(y);
        if (xr == yr) {
            return false;
        }
        if (rank[xr] < rank[yr]) {
            parent[xr] = yr;
        } else if (rank[xr] > rank[yr]) {
            parent[yr] = xr;
        } else {
            parent[yr] = xr;
            rank[xr]++;
        }
        comp--;
        return true;
    }
    long long get_components() {
        return comp;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (edges.empty()) {
        return 0;
    }
    vector<vector<long long>> edges_desc = edges;
    sort(edges_desc.begin(), edges_desc.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });
    long long max_time = 0;
    for (auto& e : edges_desc) {
        if (e[2] > max_time) max_time = e[2];
    }
    long long low = 0, high = max_time + 1;
    while (low < high) {
        long long mid = low + (high - low) / 2;
        DSU dsu(n);
        for (auto& e : edges_desc) {
            if (e[2] > mid) {
                dsu.merge(e[0], e[1]);
            } else {
                break;
            }
        }
        if (dsu.get_components() >= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
```

