#include <vector>
#include <algorithm>
using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    long long max_time_val = 0;
    for (const auto& e : edges) {
        if (e[2] > max_time_val) 
            max_time_val = e[2];
    }
    long long low = 0;
    long long high = max_time_val + 1;

    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    while (low < high) {
        long long mid = low + (high - low) / 2;
        vector<long long> parent(n);
        vector<long long> rank(n, 0);
        for (long long i = 0; i < n; i++) {
            parent[i] = i;
        }
        long long comp_count = n;

        auto find = [&](long long x) {
            long long root = x;
            while (root != parent[root]) {
                root = parent[root];
            }
            while (x != root) {
                long long next = parent[x];
                parent[x] = root;
                x = next;
            }
            return root;
        };

        auto unionSet = [&](long long x, long long y) {
            x = find(x);
            y = find(y);
            if (x == y) 
                return;
            comp_count--;
            if (rank[x] < rank[y]) {
                parent[x] = y;
            } else if (rank[x] > rank[y]) {
                parent[y] = x;
            } else {
                parent[y] = x;
                rank[x]++;
            }
        };

        for (const auto& e : edges) {
            if (e[2] <= mid) 
                break;
            long long u = e[0];
            long long v = e[1];
            unionSet(u, v);
        }

        if (comp_count >= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }

    return low;
}
```

### Explanation
1. **Binary Search Setup**: The binary search is initialized with `low = 0` and `high` set to the maximum edge time + 1. This range covers all possible values of `t`.
2. **Edge Sorting**: Edges are sorted in descending order of their removal time. This allows efficient processing during the DSU step by breaking early when edges with `time <= mid` are encountered.
3. **DSU Processing**: For each candidate `mid`, we initialize a DSU structure. Nodes start as separate components (`comp_count = n`). Edges with `time > mid` are processed by unioning their connected nodes, reducing `comp_count` for each successful union.
4. **Binary Search Adjustment**: If the number of components (`comp_count`) after processing edges is at least `k`, we adjust `high = mid` to search for a smaller `t`. Otherwise, we adjust `low = mid + 1` to search larger values.
5. **Result**: The binary search concludes when `low == high`, which is the minimal `t` satisfying the condition.

This approach efficiently narrows down the search space using binary search and leverages the DSU data structure to dynamically compute connected components, ensuring optimal performance for large inputs.
